{
  "name": "MI Options",
  "eligibility": {
    "age": 18,
    "income_limits": "No income or asset limits; open to all adults 18+, people with disabilities, Medicare beneficiaries, caregivers, and family members. (Note: Distinct from MI Choice Medicaid Waiver, which has income up to 300% of SSI/FPL for elderly/disabled.)[3][4]",
    "asset_limits": "No asset limits or tests apply.[3][4]",
    "other_requirements": ["Michigan resident", "No disability requirement for counseling access", "Includes caregivers and family members seeking guidance on long-term care or Medicare"]
  },
  "benefits": {
    "type": "service",
    "value": "Free person-centered options counseling for long-term care (exploring home/community-based services, housing, transportation, caregiver respite, planning after life events); Medicare counseling (enrollment, plans, costs, scams); personalized action plans; sessions ~90 minutes with follow-up; provided by certified counselors via network of Area Agencies on Aging, Centers for Independent Living, nonprofits.[2][3][4][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Statewide call center 800-803-7174 (8 a.m.-8 p.m. Mon-Fri) to speak with agent, schedule appointment, or get referral to local counselor[2][6]", "Local providers: e.g., AgeWays (833-801-5587 or OptionsCounseling@AgeWays.org)[6]; WellWise Services (517-592-1974 or intake.referral@wellwiseservices.org)[7]; The Senior Alliance (via local AAA)[3][4]"],
    "processing_time": "Immediate phone access; counselor appointments scheduled via call center (timeline not specified)",
    "waitlist": null,
    "forms": [],
    "documents": ["No specific documents required for initial counseling; prepare personal goals, preferences, current situation for personalized planning"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Delivered through regional network of Area Agencies on Aging (16 AAAs), Centers for Independent Living, local nonprofits; local counselors provide community-specific guidance but core service uniform statewide[2][3][4][6][7]",
    "offices_or_providers": ["Statewide call center; local: The Senior Alliance (Wayne County), AgeWays, WellWise Services (regional examples)"]
  },
  "official_source": "https://www.michigan.gov/mdhhs/inside-mdhhs/newsroom/2025/08/22/mi-options",
  "gotchas": ["Not a direct service provider or Medicaid program—provides counseling and referrals only, not benefits itself; often confused with MI Choice Waiver (which has slots, income limits, HCBS services); free but connects to potentially paid/eligibility-based programs; launched 2025, so verify current availability[1][2][3][5]"],
  "data_shape_notes": "no income/asset test; counseling/referral service via statewide call center and regional AAA/nonprofit network; distinct from entitlement-based MI Choice Waiver; open to all adults/caregivers regardless of finances"
}

{
  "name": "Senior Companion Program",
  "eligibility": {
    "age": 55,
    "income_limits": "Limited income at or below 200% of the federal poverty level; exact dollar amounts not specified in sources and vary by household size per federal guidelines (e.g., consult current HHS poverty guidelines for table). No specific table provided for Michigan.",
    "asset_limits": null,
    "other_requirements": ["Meet income eligibility guidelines", "Willing to serve a minimum of 15-20 hours per week (varies by provider: 15 hours in some, 20 in others)", "Participate in pre-service orientation and monthly in-service training", "Pass FBI fingerprinting and National Sex Offender background checks"]
  },
  "benefits": {
    "type": "service",
    "value": "One-on-one companionship and assistance with activities of daily living for adults 21+ with special needs (e.g., developmental disabilities, mental illness, frail health, dementia, physical/visual impairments, loneliness, isolation); provided by volunteer Senior Companions aged 55+ who receive tax-exempt hourly stipend, mileage reimbursement, meal assistance; service helps recipients maintain independence at home, with family, in group/nursing homes, or adult day care.",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact regional providers: e.g., Catholic Services of Macomb (phone not listed), Family Service Agency of Mid Michigan (810-257-3769), CCSEM Oakland/Macomb (248-537-3300, email lacommarec@ccsem.org), Milestone Senior Services (269-382-0515)", "Referrals from non-profit/health agencies via Memorandums of Understanding", "Pre-screening of homes/sites"],
    "processing_time": null,
    "waitlist": null,
    "forms": [null],
    "documents": ["Income verification to confirm eligibility at or below 200% poverty level", "Background check materials for FBI fingerprinting and sex offender check"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Serves 73 of 83 Michigan counties; specific providers in regions like Macomb, Oakland, Mid-Michigan, Kalamazoo area.",
    "regional_variations": "Administered by local non-profits (e.g., CCSEM for Oakland/Macomb requires 20 hours/week; Catholic Services of Macomb 15 hours; different contact points and slight hour requirements; matching via local agency referrals.",
    "offices_or_providers": ["Catholic Services of Macomb", "Family Service Agency of Mid Michigan", "CCSEM (Oakland/Macomb)", "Milestone Senior Services", "MAFG/SCP"]
  },
  "official_source": "https://www.michigan.gov/mdhhs/adult-child-serv/adults-and-seniors/acls/special-programs",
  "gotchas": ["This is a volunteer program for low-income seniors (55+) to provide services to others, not direct benefits for the elderly loved one seeking care; families request matching via referrals, not direct enrollment", "Income eligibility applies to the volunteer companion, not the care recipient (though recipients often frail/low-income)", "No statewide centralized application; must contact local providers serving your county", "Stipend for volunteers is tax-exempt and not counted as income", "Not healthcare—focuses on companionship and non-medical ADL support", "Limited to 73/83 counties; check local availability"],
  "data_shape_notes": "Federally-funded under Older Americans Act, locally administered by non-profits with regional providers and varying minimum service hours; eligibility for volunteer companions (not recipients); referral-based matching rather than direct family application"
}
